// src/mcp.ts
var text = (obj) => ({
  content: [{ type: "text", text: JSON.stringify(obj, null, 2) }]
});
async function startMcp(manager2, modes2, memory2) {
  const server = new McpServer({ name: "claude-f-me", version: "0.1.0" });
  server.registerTool(
    "list_devices",
    {
      title: "List devices",
      description: "List connected devices with their current vibration intensity (0..1), battery, the active backend mode (simulated|buttplug), the safety max-intensity cap, and the console URL.",
      inputSchema: {}
    },
    async () => text(manager2.snapshot())
  );
  server.registerTool(
    "scan_devices",
    {
      title: "Scan for devices",
      description: "Scan for nearby/available devices for the given duration, then return the updated device list.",
      inputSchema: {
        duration_ms: external_exports.number().int().min(500).max(3e4).optional().describe("scan duration in ms (default 4000)")
      }
    },
    async ({ duration_ms }) => {
      await manager2.scan(duration_ms ?? 4e3);
      return text(manager2.snapshot());
    }
  );
  server.registerTool(
    "vibrate",
    {
      title: "Vibrate",
      description: "Set vibration intensity on a device. intensity is 0..1 (0=off, 1=max). target is a device id or 'all' (default). Optionally auto-stop after duration_ms. The value is clamped to the safety max cap. Calling again replaces the current value.",
      inputSchema: {
        intensity: external_exports.number().min(0).max(1).describe("0..1 (0=off, 1=max)"),
        target: external_exports.string().optional().describe("device id or 'all' (default)"),
        duration_ms: external_exports.number().int().min(0).optional().describe("auto-stop after this many ms (recommended)")
      }
    },
    async ({ intensity, target, duration_ms }) => {
      await manager2.vibrate(target ?? "all", intensity, duration_ms);
      return text(manager2.snapshot());
    }
  );
  server.registerTool(
    "pattern",
    {
      title: "Run a pattern",
      description: "Run a sequence of intensity steps on a device. Provide a named preset (pulse|wave|escalate|tease) OR explicit steps. loops repeats the whole sequence (the device stops when it finishes). Stop or vibrate cancels a running pattern.",
      inputSchema: {
        target: external_exports.string().optional().describe("device id or 'all' (default)"),
        preset: external_exports.enum(["pulse", "wave", "escalate", "tease", "heartbeat", "staircase", "sos", "earthquake"]).optional(),
        steps: external_exports.array(
          external_exports.object({
            intensity: external_exports.number().min(0).max(1),
            ms: external_exports.number().int().min(50).max(6e4)
          })
        ).optional().describe("explicit steps; overrides preset"),
        loops: external_exports.number().int().min(1).max(50).optional().describe("repeat count (default 1)")
      }
    },
    async ({ target, preset, steps, loops }) => {
      const seq = steps && steps.length > 0 ? steps : PRESETS[preset ?? "pulse"];
      await manager2.pattern(target ?? "all", seq, loops ?? 1);
      return text({ started: true, target: target ?? "all", steps: seq.length, loops: loops ?? 1 });
    }
  );
  server.registerTool(
    "stop",
    {
      title: "Stop",
      description: "Stop a device (intensity 0) and cancel any running pattern. target is a device id or 'all' (default).",
      inputSchema: { target: external_exports.string().optional().describe("device id or 'all' (default)") }
    },
    async ({ target }) => {
      await manager2.stop(target ?? "all");
      return text(manager2.snapshot());
    }
  );
  server.registerTool(
    "emergency_stop",
    {
      title: "Emergency stop",
      description: "Immediately stop ALL devices and cancel ALL patterns. Use when anything feels wrong.",
      inputSchema: {}
    },
    async () => {
      await manager2.stopAll();
      return text({ stopped: true });
    }
  );
  server.registerTool(
    "set_max_intensity",
    {
      title: "Set safety max intensity",
      description: "Set the global safety cap (0..1). All current and future intensities are clamped to this value. Lower it to keep things gentle.",
      inputSchema: { value: external_exports.number().min(0).max(1).describe("0..1") }
    },
    async ({ value }) => {
      manager2.setMaxIntensity(value);
      return text({ maxIntensity: manager2.maxIntensity });
    }
  );
  server.registerTool(
    "load_funscript",
    {
      title: "Load a funscript (video mode)",
      description: "Load a Funscript timeline so it can be played in video mode. `source` is either the funscript JSON itself (a string starting with '{') or a path to a .funscript/.json file. Returns the action count and duration.",
      inputSchema: {
        source: external_exports.string().describe("funscript JSON string, or a file path to a .funscript")
      }
    },
    async ({ source }) => text(await modes2.loadFunscript(source))
  );
  server.registerTool(
    "play_video",
    {
      title: "Play loaded funscript",
      description: "Play the currently loaded funscript in real time, mapping position 0..100 to intensity 0..1 (clamped to the safety cap). Use load_funscript first. Cancels any other running mode.",
      inputSchema: {
        target: external_exports.string().optional().describe("device id or 'all' (default)"),
        loop: external_exports.boolean().optional().describe("repeat when it ends (default false)"),
        speed: external_exports.number().min(0.1).max(4).optional().describe("playback speed (default 1)"),
        invert: external_exports.boolean().optional().describe("invert position (default false)")
      }
    },
    async ({ target, loop, speed, invert }) => text(await modes2.playVideo(target ?? "all", { loop, speed, invert }))
  );
  server.registerTool(
    "start_game",
    {
      title: "Start a game mode",
      description: "Start a built-in interactive game engine. roulette = random bursts at random intervals; escalation = ramps up and holds at max; ambient = gentle organic waves; edge = tease-and-deny (ramp to the brink, then cut and rest, peak creeps higher); wheel = spin through random levels then land and hold. Cancels any other running mode.",
      inputSchema: {
        type: external_exports.enum(["roulette", "escalation", "ambient", "edge", "wheel"]),
        target: external_exports.string().optional().describe("device id or 'all' (default)"),
        intensity_max: external_exports.number().min(0).max(1).optional().describe("ceiling for this game (default 1)"),
        duration_ms: external_exports.number().int().min(1e3).optional().describe("auto-end after this long")
      }
    },
    async ({ type, target, intensity_max, duration_ms }) => text(await modes2.startGame(target ?? "all", type, { intensityMax: intensity_max, durationMs: duration_ms }))
  );
  server.registerTool(
    "game_event",
    {
      title: "Fire a game event",
      description: "One-shot reaction for a narrative game you (the assistant) are running: reward / penalty / tease / pulse. magnitude 0..1 scales it. Good for text adventures \u2014 e.g. 'you found treasure' \u2192 reward.",
      inputSchema: {
        kind: external_exports.enum(["reward", "penalty", "tease", "pulse"]),
        target: external_exports.string().optional().describe("device id or 'all' (default)"),
        magnitude: external_exports.number().min(0).max(1).optional().describe("0..1 (default 0.7)")
      }
    },
    async ({ kind, target, magnitude }) => text(await modes2.gameEvent(target ?? "all", kind, magnitude))
  );
  server.registerTool(
    "stop_mode",
    {
      title: "Stop the active mode",
      description: "Stop any running video or game mode and turn the device off.",
      inputSchema: { target: external_exports.string().optional() }
    },
    async ({ target }) => {
      modes2.stop();
      await manager2.stop(target ?? "all");
      return text(manager2.snapshot());
    }
  );
  server.registerTool(
    "compose",
    {
      title: "Compose & play a Muse score",
      description: "YOU compose a haptic timeline from a creative brief and play it \u2014 the device becomes an instrument you play. Provide `keyframes` as [{at,level}] where `at` is ms from the start (strictly increasing, starting at 0) and `level` is intensity 0..1. Use many keyframes for smooth ramps, plateaus to hold, drops to 0 for denial/rest, and a release near the end; scores can run for minutes. `brief` is the natural-language idea you turned into the score (shown in the console). Optionally save_as a library name. Respects the safety cap. Cancels any other running mode.",
      inputSchema: {
        brief: external_exports.string().describe("the vibe you composed, in words (e.g. '10-minute tantric slow burn')"),
        keyframes: external_exports.array(external_exports.object({ at: external_exports.number().min(0), level: external_exports.number().min(0).max(1) })).min(2).describe("[{at:ms, level:0..1}] timeline, at strictly increasing from 0"),
        target: external_exports.string().optional().describe("device id or 'all' (default)"),
        save_as: external_exports.string().optional().describe("save to the Muse library under this name"),
        loop: external_exports.boolean().optional().describe("repeat when it ends (default false)")
      }
    },
    async ({ brief, keyframes, target, save_as, loop }) => {
      const score = { brief, keyframes, by: "claude" };
      if (save_as) await modes2.saveScore(save_as, score);
      const r = await modes2.playScore(target ?? "all", score, { loop });
      return text({ ...r, brief, keyframes: keyframes.length, saved: save_as ?? null });
    }
  );
  server.registerTool(
    "muse_list",
    {
      title: "List Muse library",
      description: "List saved/built-in Muse scores (name, brief, duration, keyframe count) you can replay with muse_play.",
      inputSchema: {}
    },
    async () => text(modes2.listScores())
  );
  server.registerTool(
    "muse_play",
    {
      title: "Play a Muse score",
      description: "Play a score from the Muse library by name (see muse_list). Cancels any other running mode.",
      inputSchema: {
        name: external_exports.string().describe("library score name"),
        target: external_exports.string().optional().describe("device id or 'all' (default)"),
        loop: external_exports.boolean().optional()
      }
    },
    async ({ name, target, loop }) => {
      const score = modes2.getScore(name);
      if (!score) throw new Error(`no Muse score named "${name}" \u2014 try muse_list`);
      return text(await modes2.playScore(target ?? "all", score, { loop }));
    }
  );
  server.registerTool(
    "list_personas",
    {
      title: "List personas",
      description: "List driver personas. Each shapes the feel of games/events (pace, randomness, denial, ceiling) and, when a matching API key is set, which model composes Muse scores. Pick one with set_persona.",
      inputSchema: {}
    },
    async () => text(modes2.listPersonas())
  );
  server.registerTool(
    "set_persona",
    {
      title: "Set the driver persona",
      description: "Choose who's in control. Pass a persona id (slowburn|brat|metronome|storm|oracle) or 'blind' to pick a random hidden one (label shows \u{1F3AD} ??? until reveal_persona). Changes how subsequent games and game_events feel.",
      inputSchema: { id: external_exports.string().describe("persona id, or 'blind'") }
    },
    async ({ id }) => {
      const r = modes2.setPersona(id);
      return text({ ...r, persona: manager2.snapshot().persona });
    }
  );
  server.registerTool(
    "reveal_persona",
    {
      title: "Reveal a blind persona",
      description: "Reveal the identity of a persona chosen via blind mode.",
      inputSchema: {}
    },
    async () => text(modes2.reveal())
  );
  server.registerTool(
    "remember",
    {
      title: "Remember something",
      description: "Save a preference, limit, or note to local memory (e.g. 'loves heartbeat at 60%', 'never go above 70%', 'safeword is red'). Stored only on this machine.",
      inputSchema: { note: external_exports.string().describe("the thing to remember") }
    },
    async ({ note }) => {
      memory2.remember(note);
      return text({ remembered: note });
    }
  );
  server.registerTool(
    "recall",
    {
      title: "Recall memory",
      description: "Return what's known about this user from local memory: notes, favourite games/scores, persona affinity, soft dislike signals (things stopped right after starting), and any comfort ceiling. Consult before composing or escalating.",
      inputSchema: {}
    },
    async () => text(memory2.recall())
  );
  server.registerTool(
    "forget",
    {
      title: "Forget everything",
      description: "Wipe all local memory (notes, history, learned signals). Irreversible.",
      inputSchema: {}
    },
    async () => {
      await memory2.forget();
      return text({ forgotten: true });
    }
  );
  for (const p of PROMPTS) {
    server.registerPrompt(
      p.name,
      { title: p.title, description: p.description },
      () => ({ messages: [{ role: "user", content: { type: "text", text: p.text } }] })
    );
  }
  const transport = new StdioServerTransport();
  await server.connect(transport);
}

